export type DocsHelpCenterItem = {
  key: string;
  title: string;
  status?: "active" | "draft" | "archived";
  metadata?: Record<string, unknown>;
};

export function createDocsHelpCenterItem(item: DocsHelpCenterItem) {
  return {
    key: item.key,
    title: item.title,
    status: item.status ?? "active",
    metadata: item.metadata ?? {},
  };
}

export const docsHelpCenterChecklist = [
  "Confirm ownership boundaries",
  "Wire persistence or provider adapter",
  "Add audit events for sensitive changes",
] as const;

const items = [
  { title: "Configure", description: "Set ownership, defaults, and permissions." },
  { title: "Operate", description: "Review status, recent activity, and unresolved work." },
  { title: "Verify", description: "Run the checklist before enabling this module in production." },
];

export default function DocsHelpCenterPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Docs Help Center</h1>
        <p className="text-muted-foreground">Help center index, article metadata, and support escalation paths.</p>
      </div>
      <div className="grid gap-3 md:grid-cols-3">
        {items.map((item) => (
          <section key={item.title} className="rounded-lg border p-4">
            <h2 className="font-medium">{item.title}</h2>
            <p className="text-sm text-muted-foreground">{item.description}</p>
          </section>
        ))}
      </div>
    </main>
  );
}
